import { Injectable, Logger } from '@nestjs/common';
import { HttpService } from '@nestjs/axios';
import { ConfigService } from '@nestjs/config';
import { firstValueFrom } from 'rxjs';

@Injectable()
export class KybService {
  private readonly logger = new Logger(KybService.name);
  private readonly baseUrl = 'https://api.prembly.com';

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
  ) {}

  async verifyBusiness(registrationNumber: string, companyType: string) {
    const apiKey = this.configService.get<string>('PREMBLY_API_KEY');
    const appId = this.configService.get<string>('PREMBLY_APP_ID');

    const url = `${this.baseUrl}/identitypass/verification/business/cac`;

    const data = {
      registration_number: registrationNumber,
      company_type: companyType,
    };

    const headers = {
      'x-api-key': apiKey,
      'app-id': appId,
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };

    try {
      this.logger.log(`Initiating KYB verification for ${registrationNumber}`);
      const response = await firstValueFrom(
        this.httpService.post(url, data, { headers }),
      );
      return response.data;
    } catch (error) {
      this.logger.error(`KYB verification failed: ${error.message}`);
      if (error.response) {
        return error.response.data;
      }
      throw error;
    }
  }
}

